// Fix del rediseño de ChiquiTeCuenta:
//
// 1) components/ChiquiTeCuenta.tsx
//    - Quita las imágenes de Chiqui de DENTRO de cada tarjeta
//      (estaban causando imágenes rotas)
//    - Solo el HEADER tiene img de Chiqui (chiqui_lentes.png)
//    - Cada tarjeta: badge + emoji + titulo + PREGUNTA + Ver más
//    - 25 preguntas por especie actualizadas con las correctas
//
// 2) components/DashboardContenido.tsx
//    - Agrega imágenes de Chiqui en los HEADERS de secciones:
//      🔍 Próximos → chiqui_lupa.png
//      🏥 Cuidados recientes → chiqui_doctor.png
//      (Chiqui te cuenta ya tiene chiqui_lentes en su propio header)
//
// 3) app/registro-diario/page.tsx — heces mejorado (igual que antes)

const fs = require('fs'); const path = require('path');
function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64,'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir,{recursive:true});
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}
escribir('components/ChiquiTeCuenta.tsx', "");
escribir('components/DashboardContenido.tsx', "");
escribir('app/registro-diario/page.tsx', "");
